	for i := 0; i < m; i++ {
		u := arr[2+3*i]
		v := arr[2+3*i+1]
		w := arr[2+3*i+2]

		if u >= 0 && u < n && v >= 0 && v < n {
			adj[u] = append(adj[u], Edge{to: v, weight: w})
		}
	}

	hIndex := 2 + 3*m + 2

