	}

	gScore[start] = 0
	heap.Push(openSet, &Node{id: start, f: arr[hIndex+start], g: 0})

	for openSet.Len() > 0 {
		current := heap.Pop(openSet).(*Node)
		u := current.id

		if u == goal {
