        for (int i = 0; i < m; i++) {
            int u = arr[2 + 3 * i];
            int v = arr[2 + 3 * i + 1];
            int w = arr[2 + 3 * i + 2];

            if (u >= 0 && u < n && v >= 0 && v < n) {
                adj[u].add(new Edge(v, w));
            }
        }

        int hIndex = 2 + 3 * m + 2;

        PriorityQueue<Node> openSet = new PriorityQueue<>();
        int[] gScore = new int[n];
