#[derive(Copy, Clone, Eq, PartialEq)]
struct Node {
    id: usize,
    f: i32,
    g: i32,
}

impl Ord for Node {
    fn cmp(&self, other: &Self) -> Ordering {
        other.f.cmp(&self.f) // Min-heap
    }
}

impl PartialOrd for Node {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

struct Edge {
    to: usize,
    weight: i32,
}

pub fn a_star_search(arr: &[i32]) -> i32 {
    if arr.len() < 2 {
        return -1;
    }

    let n = arr[0] as usize;
    let m = arr[1] as usize;

    if arr.len() < 2 + 3 * m + 2 + n {
        return -1;
    }

    let start = arr[2 + 3 * m] as usize;
    let goal = arr[2 + 3 * m + 1] as usize;

    if start >= n || goal >= n {
        return -1;
    }
    if start == goal {
        return 0;
    }

    let mut adj = vec![Vec::new(); n];
    for i in 0..m {
        let u = arr[2 + 3 * i] as usize;
        let v = arr[2 + 3 * i + 1] as usize;
        let w = arr[2 + 3 * i + 2];

        if u < n && v < n {
            adj[u].push(Edge { to: v, weight: w });
        }
    }

    let h_index = 2 + 3 * m + 2;

    let mut open_set = BinaryHeap::new();
    let mut g_score = vec![i32::MAX; n];

    g_score[start] = 0;
    open_set.push(Node {
        id: start,
        f: arr[h_index + start],
        g: 0,
    });

    while let Some(current) = open_set.pop() {
        let u = current.id;

        if u == goal {
            return current.g;
        }

        if current.g > g_score[u] {
            continue;
        }

        for e in &adj[u] {
            let v = e.to;
            let w = e.weight;

            if g_score[u] != i32::MAX && g_score[u] + w < g_score[v] {
                g_score[v] = g_score[u] + w;
                let f = g_score[v] + arr[h_index + v];
                open_set.push(Node {
                    id: v,
                    f,
                    g: g_score[v],
                });
            }
        }
    }

    -1
}

import scala.collection.mutable

/**
 * A* search algorithm to find shortest path from start to goal.
 */
object AStar {
  def aStar(
    adjList: Map[Int, List[(Int, Int)]],
    start: Int,
    goal: Int,
    heuristic: Map[Int, Int]
  ): (List[Int], Double) = {
    if (start == goal) return (List(start), 0.0)

    val gScore = mutable.Map[Int, Double]()
    val cameFrom = mutable.Map[Int, Int]()
    val closedSet = mutable.Set[Int]()

    for (node <- adjList.keys) {
      gScore(node) = Double.PositiveInfinity
    }
    gScore(start) = 0.0

    // Priority queue: (fScore, node)
    val pq = mutable.PriorityQueue[(Double, Int)]()(Ordering.by[(Double, Int), Double](-_._1))
    pq.enqueue((heuristic.getOrElse(start, 0).toDouble, start))

    while (pq.nonEmpty) {
      val (_, currentNode) = pq.dequeue()

      if (currentNode == goal) {
        val path = mutable.ListBuffer[Int]()
        var node = goal
        while (cameFrom.contains(node)) {
          path.prepend(node)
          node = cameFrom(node)
        }
        path.prepend(node)
        return (path.toList, gScore(goal))
      }

      if (!closedSet.contains(currentNode)) {
        closedSet.add(currentNode)

        for ((neighbor, weight) <- adjList.getOrElse(currentNode, List.empty)) {
          if (!closedSet.contains(neighbor)) {
            val tentativeG = gScore(currentNode) + weight
            if (tentativeG < gScore.getOrElse(neighbor, Double.PositiveInfinity)) {
              cameFrom(neighbor) = currentNode
              gScore(neighbor) = tentativeG
              val fScore = tentativeG + heuristic.getOrElse(neighbor, 0)
              pq.enqueue((fScore, neighbor))
            }
          }
        }
      }
    }

    (List.empty, Double.PositiveInfinity)
  }

  def main(args: Array[String]): Unit = {
    val adjList = Map(
      0 -> List((1, 1), (2, 4)),
      1 -> List((2, 2), (3, 6)),
      2 -> List((3, 3)),
      3 -> List()
    )
    val heuristic = Map(0 -> 5, 1 -> 4, 2 -> 2, 3 -> 0)

    val (path, cost) = aStar(adjList, 0, 3, heuristic)
    println(s"Path: $path, Cost: $cost")
  }
}

package algorithms.graph.astarsearch

import scala.collection.mutable
import scala.math.Ordering

object AStarSearch {
  case class Node(id: Int, f: Int, g: Int) extends Ordered[Node] {
    def compare(that: Node): Int = that.f - this.f // Min-heap
  }

  case class Edge(to: Int, weight: Int)

  def solve(arr: Array[Int]): Int = {
    if (arr.length < 2) return -1

    val n = arr(0)
    val m = arr(1)

    if (arr.length < 2 + 3 * m + 2 + n) return -1

    val start = arr(2 + 3 * m)
    val goal = arr(2 + 3 * m + 1)

    if (start < 0 || start >= n || goal < 0 || goal >= n) return -1
    if (start == goal) return 0

    val adj = Array.fill(n)(new mutable.ListBuffer[Edge])
    for (i <- 0 until m) {
      val u = arr(2 + 3 * i)
      val v = arr(2 + 3 * i + 1)
      val w = arr(2 + 3 * i + 2)

      if (u >= 0 && u < n && v >= 0 && v < n) {
        adj(u).append(Edge(v, w))
      }
    }

    val hIndex = 2 + 3 * m + 2

    val openSet = mutable.PriorityQueue.empty[Node]
    val gScore = Array.fill(n)(Int.MaxValue)

    gScore(start) = 0
    openSet.enqueue(Node(start, arr(hIndex + start), 0))

    while (openSet.nonEmpty) {
      val current = openSet.dequeue()
      val u = current.id

      if (u == goal) return current.g

      if (current.g <= gScore(u)) {
        for (e <- adj(u)) {
          val v = e.to
          val w = e.weight

          if (gScore(u) != Int.MaxValue && gScore(u).toLong + w < gScore(v)) {
            gScore(v) = gScore(u) + w
            val f = gScore(v) + arr(hIndex + v)
            openSet.enqueue(Node(v, f, gScore(v)))
          }
        }
      }
    }

    -1
  }
}

/// A* search algorithm to find shortest path from start to goal.
/// Returns (path, cost).
func aStar(adjList: [Int: [[Int]]], start: Int, goal: Int, heuristic: [Int: Int]) -> (path: [Int], cost: Double) {
    if start == goal {
        return ([start], 0)
    }

    var gScore = [Int: Double]()
    var cameFrom = [Int: Int]()
    var closedSet = Set<Int>()

    for node in adjList.keys {
        gScore[node] = Double.infinity
    }
    gScore[start] = 0

    // Simple priority queue using array (sorted insertion)
    var openSet: [(fScore: Double, node: Int)] = [(Double(heuristic[start] ?? 0), start)]

    while !openSet.isEmpty {
        // Get node with minimum fScore
        openSet.sort { $0.fScore < $1.fScore }
        let current = openSet.removeFirst()
        let currentNode = current.node

        if currentNode == goal {
            // Reconstruct path
            var path = [Int]()
            var node = goal
            while let prev = cameFrom[node] {
                path.insert(node, at: 0)
                node = prev
            }
            path.insert(node, at: 0)
            return (path, gScore[goal]!)
        }

        if closedSet.contains(currentNode) { continue }
        closedSet.insert(currentNode)

        if let neighbors = adjList[currentNode] {
            for edge in neighbors {
                let neighbor = edge[0]
                let weight = edge[1]

                if closedSet.contains(neighbor) { continue }

                let tentativeG = gScore[currentNode]! + Double(weight)
                if tentativeG < (gScore[neighbor] ?? Double.infinity) {
                    cameFrom[neighbor] = currentNode
                    gScore[neighbor] = tentativeG
                    let fScore = tentativeG + Double(heuristic[neighbor] ?? 0)
                    openSet.append((fScore, neighbor))
                }
            }
        }
    }

    return ([], Double.infinity)
}

func aStarSearch(_ arr: [Int]) -> Int {
    if arr.count < 2 { return -1 }

    let n = arr[0]
    let m = arr[1]
    let expectedCount = 2 + (3 * m) + n + 2
    if n <= 0 || arr.count < expectedCount { return -1 }

    var index = 2
    var adjList: [Int: [[Int]]] = [:]
    for node in 0..<n {
        adjList[node] = []
    }

    for _ in 0..<m {
        let u = arr[index]
        let v = arr[index + 1]
        let w = arr[index + 2]
        index += 3
        adjList[u, default: []].append([v, w])
    }

    let start = arr[index]
    let goal = arr[index + 1]
    index += 2

    var heuristic: [Int: Int] = [:]
    for node in 0..<n {
        heuristic[node] = arr[index]
        index += 1
    }

    let result = aStar(adjList: adjList, start: start, goal: goal, heuristic: heuristic)
    return result.cost.isInfinite ? -1 : Int(result.cost)
}

